var messages = $.steps.listEmails.response.messages || [];
var emailList = '';
messages.slice(0, 30).forEach(function(m, i) {
  var headers = m.payload && m.payload.headers ? m.payload.headers : [];
  var subject = '';
  var from = '';
  var date = '';
  headers.forEach(function(h) {
    if (h.name === 'Subject') subject = h.value || '';
    if (h.name === 'From') from = h.value || '';
    if (h.name === 'Date') date = h.value || '';
  });
  var snippet = m.snippet || '';
  emailList += (i + 1) + '. Subject: ' + subject + '\n';
  emailList += '   From: ' + from + '\n';
  emailList += '   Date: ' + date + '\n';
  emailList += '   Snippet: ' + snippet.slice(0, 200) + '\n\n';
});
return { emailList: emailList, emailCount: messages.length };

var cats = $.input.categories || 'Work, Personal, Marketing, Notifications, Urgent, Spam';
var prompt = 'You are an email categorization AI. Analyze each email below and assign it a category, priority level, and brief summary.

';
prompt += 'AVAILABLE CATEGORIES: ' + cats + '

';
prompt += 'EMAILS TO CATEGORIZE (' + $.steps.extractEmails.output.emailCount + ' emails):
';
prompt += $.steps.extractEmails.output.emailList + '
';
prompt += 'INSTRUCTIONS:
';
prompt += '- Assign exactly one category from the list above to each email
';
prompt += '- Set priority: High, Medium, or Low
';
prompt += '- Write a 1-sentence summary
';
prompt += '- Flag any emails that need immediate attention

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "emails": [
';
prompt += '    { "number": 1, "subject": "...", "from": "...", "category": "...", "priority": "High|Medium|Low", "summary": "...", "needsAttention": true }
';
prompt += '  ],
';
prompt += '  "stats": { "total": 0, "byCategory": {}, "highPriority": 0 },
';
prompt += '  "topAction": "Most important email to address first"
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiCategorize.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { emails: [], stats: { total: 0, byCategory: {}, highPriority: 0 }, topAction: raw }; }

var ai = $.steps.parseAI.output;
var emails = ai.emails || [];
var date = new Date().toISOString().split('T')[0];
var sheetData = emails.map(function(e) {
  return {
    'Number': e.number || '',
    'Subject': (e.subject || '').slice(0, 200),
    'From': (e.from || '').slice(0, 100),
    'Category': e.category || '',
    'Priority': e.priority || '',
    'Summary': (e.summary || '').slice(0, 300),
    'Needs Attention': e.needsAttention ? 'Yes' : 'No',
    'Date Categorized': date
  };
});
return { sheetData: sheetData, emailCount: emails.length, date: date };

var ai = $.steps.parseAI.output;
var stats = ai.stats || {};
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Email Categorization Report', emoji: true } });
var byCategory = stats.byCategory || {};
var catLines = Object.keys(byCategory).map(function(k) { return k + ': ' + byCategory[k]; }).join(' | ');
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Total Emails:*\n' + (stats.total || 0) },
  { type: 'mrkdwn', text: '*High Priority:*\n' + (stats.highPriority || 0) }
] });
if (catLines) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Categories:* ' + catLines } });
}
blocks.push({ type: 'divider' });
if (ai.topAction) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Top Action:* ' + ai.topAction } });
}
var emails = ai.emails || [];
var urgent = emails.filter(function(e) { return e.needsAttention; });
if (urgent.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Needs Attention:*' } });
  urgent.slice(0, 5).forEach(function(e) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '- *' + (e.subject || 'No subject') + '* from ' + (e.from || 'unknown') + '\n  ' + (e.summary || '') } });
  });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Categorized with Claude AI via One CLI' }] });
var fallback = 'Email Report: ' + (stats.total || 0) + ' emails categorized, ' + (stats.highPriority || 0) + ' high priority';
return { blocks: blocks, fallback: fallback };
